void test_insert_back(void) {
    DList list = {NULL, NULL};
    insert_back(&list, 1);
    insert_back(&list, 2);
    insert_back(&list, 3);
    TEST_ASSERT_NOT_NULL(list.head);
    TEST_ASSERT_NOT_NULL(list.tail);
    TEST_ASSERT_EQUAL_INT(1, list.head->val);
    TEST_ASSERT_EQUAL_INT(3, list.tail->val);
    free_list(&list);
}

void test_insert_front(void) {
    DList list = {NULL, NULL};
    insert_back(&list, 1);
    insert_back(&list, 2);
    insert_front(&list, 0);
    TEST_ASSERT_EQUAL_INT(0, list.head->val);
    TEST_ASSERT_EQUAL_INT(2, list.tail->val);
    TEST_ASSERT_NOT_NULL(list.head->next);
    TEST_ASSERT_EQUAL_INT(1, list.head->next->val);
    free_list(&list);
}

void test_forward_traversal(void) {
    DList list = {NULL, NULL};
    insert_back(&list, 10);
    insert_back(&list, 20);
    insert_back(&list, 30);
    int vals[3] = {10, 20, 30};
    int i = 0;
    for (DNode *c = list.head; c; c = c->next) {
        TEST_ASSERT_EQUAL_INT(vals[i], c->val);
        i++;
    }
    TEST_ASSERT_EQUAL_INT(3, i);
    free_list(&list);
}

void test_backward_traversal(void) {
    DList list = {NULL, NULL};
    insert_back(&list, 100);
    insert_back(&list, 200);
    insert_back(&list, 300);
    int vals[3] = {300, 200, 100};
    int i = 0;
    for (DNode *c = list.tail; c; c = c->prev) {
        TEST_ASSERT_EQUAL_INT(vals[i], c->val);
        i++;
    }
    TEST_ASSERT_EQUAL_INT(3, i);
    free_list(&list);
}

int main(void) {
    RUN_TEST(test_insert_back);
    RUN_TEST(test_insert_front);
    RUN_TEST(test_forward_traversal);
    RUN_TEST(test_backward_traversal);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

