#include <stdlib.h>

/* == EXEMPLE ================================================
 * Deque (double-ended queue) avec push_front et push_back
 * Chaque noeud a prev et next pour parcours bidirectionnel.
 * =========================================================== */
typedef struct QNode { char c; struct QNode *prev, *next; } QNode;
typedef struct { QNode *head, *tail; } Deque;

void example_push_back(Deque *d, char c) {
    QNode *n = malloc(sizeof(QNode));
    if (!n) return;
    n->c = c; n->prev = d->tail; n->next = NULL;
    if (d->tail) d->tail->next = n;
    d->tail = n;
    if (!d->head) d->head = n;
}
void example_demo(void) {
    Deque d = {NULL, NULL};
    example_push_back(&d, 'A');
    example_push_back(&d, 'B');
    example_push_back(&d, 'C');
    for (QNode *c = d.head; c; c = c->next) printf("%c ", c->c);
    printf("\n");
    for (QNode *c = d.tail; c; c = c->prev) printf("%c ", c->c);
    printf("\n");
    QNode *c = d.head;
    while (c) { QNode *t = c->next; free(c); c = t; }
}
/* Resultat: A B C / C B A */

